Code.Terraform:
```hcl
resource "aws_cloudtrail" "<example_resource_name>" {
  name           = "<example_resource_name>"
  s3_bucket_name = "<example_resource_name>"

  event_selector {
    data_resource {
      type   = "AWS::Lambda::Function"  # 重要：Lambdaデータイベントを有効化
      values = ["arn:aws:lambda:<REGION>:<ACCOUNT_ID>:function"]  # 重要：このアカウント/リージョン内のすべての関数のInvokeをキャプチャ
    }
  }
}
```
